Integer wrappedNum = 42;
int primitiveNum = wrappedNum; // unboxing -- happens automatically

System.out.println(primitiveNum + 8);

import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        ArrayList<Integer> numbers = new ArrayList<>();

        numbers.add(10); // int 10 is autoboxed into Integer
        numbers.add(20);

        int first = numbers.get(0); // Integer is unboxed into int
        System.out.println(first + 5);
    }
}

Integer a = 100;
Integer b = 100;
System.out.println(a == b); // true

Integer c = 200;
Integer d = 200;
System.out.println(c == d); // false!

Integer c = 200;
Integer d = 200;
System.out.println(c.equals(d)); // true -- always reliable

import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        ArrayList<Integer> scores = new ArrayList<>();
        scores.add(88);
        scores.add(92);
        scores.add(79);

        int total = 0;
        for (int score : scores) {
            total += score;
        }

        System.out.println("Total: " + total);
    }
}

